// =====================================================
// AUDITORÍA DIARIA SICI v3.0 - Mobile Friendly
// =====================================================
// Cambios v3.0:
//   - Agregado LLM Enrichment Venta (stats + health)
//   - Agregado pipelines alquiler a workflows
//   - Limpiados health hardcodeados (Export 7AM, Super 8PM)
//   - Limpiadas referencias a sin_match_exportados
//   - Simplificado Stats Sin Match

const statsProp = $('PG: Stats Propiedades').first().json;
const statsMatch = $('PG: Stats Matching').first().json;
const statsProy = $('PG: Stats Proyectos').first().json;
const statsSinMatch = $('PG: Stats Sin Match').first().json;
const statsTC = $('PG: Stats TC').first().json;

let enriqStats;
try {
  enriqStats = $('PG: Stats Enriquecimiento').first().json;
} catch (e) {
  enriqStats = { nuevos_agregados: 0, total_pendientes: 0, alta_prioridad: 0 };
}

const enriqNuevos = parseInt(enriqStats?.nuevos_agregados) || 0;
const enriqPendientes = parseInt(enriqStats?.total_pendientes) || 0;
const enriqAltaPrioridad = parseInt(enriqStats?.alta_prioridad) || 0;

// ===== PROPIEDADES =====
const total = parseInt(statsProp.total) || 0;
const completadas = parseInt(statsProp.completadas) || 0;
const nuevas = parseInt(statsProp.nuevas) || 0;
const inactivoPending = parseInt(statsProp.inactivo_pending) || 0;
const inactivoConfirmed = parseInt(statsProp.inactivo_confirmed) || 0;
const excluidasOp = parseInt(statsProp.excluidas_operacion) || 0;
const matcheadas = parseInt(statsProp.matcheadas) || 0;
const sinMatch = parseInt(statsProp.sin_match) || 0;
const conNombre = parseInt(statsProp.con_nombre) || 0;
const pendientesEnrich = parseInt(statsProp.pendientes_enrich) || 0;
const creadas24h = parseInt(statsProp.creadas_24h) || 0;
const enriquecidas24h = parseInt(statsProp.enriquecidas_24h) || 0;

const pctMatch = completadas > 0 ? ((matcheadas / completadas) * 100).toFixed(1) : 0;
const pctNombre = completadas > 0 ? ((conNombre / completadas) * 100).toFixed(1) : 0;
const pctHuerfanas = completadas > 0 ? ((sinMatch / completadas) * 100).toFixed(1) : 0;

// ===== ALQUILER (v3.0) =====
const alqCompletadas = parseInt(statsProp.alq_completadas) || 0;
const alqCreadas24h = parseInt(statsProp.alq_creadas_24h) || 0;
const alqLlmEnriched = parseInt(statsProp.alq_llm_enriched) || 0;
const alqMatcheadas = parseInt(statsProp.alq_matcheadas) || 0;
const alqPctMatch = alqCompletadas > 0 ? ((alqMatcheadas / alqCompletadas) * 100).toFixed(1) : 0;

// ===== LLM ENRICHMENT (v3.0) =====
const llmEnrichedVenta = parseInt(statsProp.llm_enriched_venta) || 0;
const llmPendientesVenta = parseInt(statsProp.llm_pendientes_venta) || 0;
const enrichmentLlmOk = statsProp.enrichment_llm_venta_ok === true || statsProp.enrichment_llm_venta_ok === 'true';
const horasSinEnrichmentLlm = parseFloat(statsProp.horas_sin_enrichment_llm) || 0;

// ===== CALIDAD =====
const scoreAlto = parseInt(statsProp.score_alto) || 0;
const scoreMedio = parseInt(statsProp.score_medio) || 0;
const scoreBajo = parseInt(statsProp.score_bajo) || 0;
const totalScores = scoreAlto + scoreMedio + scoreBajo;
const pctAlto = totalScores > 0 ? Math.round((scoreAlto / totalScores) * 100) : 0;
const pctMedio = totalScores > 0 ? Math.round((scoreMedio / totalScores) * 100) : 0;
const pctBajo = totalScores > 0 ? Math.round((scoreBajo / totalScores) * 100) : 0;

const sinZona = parseInt(statsProp.sin_zona) || 0;
const sinDorms = parseInt(statsProp.sin_dormitorios) || 0;
const sinNombreField = parseInt(statsProp.sin_nombre) || 0;
const sinPrecio = parseInt(statsProp.sin_precio) || 0;
const discrepanciasMerge = parseInt(statsProp.discrepancias_merge) || 0;

// ===== MATCHING =====
const sugerencias24h = parseInt(statsMatch.sugerencias_24h) || 0;
const aprobadas24h = parseInt(statsMatch.aprobadas_24h) || 0;
const rechazadas24h = parseInt(statsMatch.rechazadas_24h) || 0;
const pendientesMatching = parseInt(statsMatch.pendientes_matching) || 0;
const matchingNocturnoHoy = parseInt(statsMatch.matching_nocturno_hoy) || 0;
const totalSugerencias = parseInt(statsMatch.sugerencias_total) || 0;

const tasaAprobacion = (aprobadas24h + rechazadas24h) > 0
  ? Math.round((aprobadas24h / (aprobadas24h + rechazadas24h)) * 100) + '%'
  : 'N/A';

// ===== SIN MATCH =====
const huerfanasActivas = parseInt(statsSinMatch.huerfanas_activas) || 0;

// ===== PROYECTOS =====
const proyTotal = parseInt(statsProy.total) || 0;
const proyGpsVerificado = parseInt(statsProy.gps_verificado) || 0;
const proyConPlaceId = parseInt(statsProy.con_place_id) || 0;
const proyPendientesGoogle = parseInt(statsProy.pendientes_google) || 0;
const proyActivos = parseInt(statsProy.activos) || 0;
const pctGpsVerificado = proyActivos > 0 ? ((proyGpsVerificado / proyActivos) * 100).toFixed(1) : 0;
const proyConDesarrollador = parseInt(statsProy.con_desarrollador) || 0;
const proySinDesarrollador = parseInt(statsProy.sin_desarrollador) || 0;
const pctSinDesarrollador = proyActivos > 0 ? ((proySinDesarrollador / proyActivos) * 100).toFixed(1) : 0;

// ===== TC DINÁMICO =====
const tcParalelo = statsTC.tc_paralelo || 'N/A';
const tcOficial = statsTC.tc_oficial || 'N/A';
const consultasBinance24h = parseInt(statsTC.consultas_binance_24h) || 0;

// ===== HEALTH CHECK =====
const discoveryOk = statsProp.discovery_ok === true || statsProp.discovery_ok === 'true';
const tcDinamicoOk = statsProp.tc_dinamico_ok === true || statsProp.tc_dinamico_ok === 'true';
const horasSinEnrichment = parseFloat(statsProp.horas_sin_enrichment) || 0;
const horasSinMerge = parseFloat(statsProp.horas_sin_merge) || 0;
const enrichmentOk = horasSinEnrichment < 26;
const mergeOk = horasSinMerge < 26;
const matchingNocturnoOk = matchingNocturnoHoy > 0;

// ===== HEALTH ALQUILER (v3.0) =====
const discoveryAlqOk = statsProp.discovery_alquiler_ok === true || statsProp.discovery_alquiler_ok === 'true';
const enrichmentAlqOk = statsProp.enrichment_alquiler_ok === true || statsProp.enrichment_alquiler_ok === 'true';
const mergeAlqOk = statsProp.merge_alquiler_ok === true || statsProp.merge_alquiler_ok === 'true';
const verificadorAlqOk = statsProp.verificador_alquiler_ok === true || statsProp.verificador_alquiler_ok === 'true';

// ===== ALERTAS =====
const alertItems = [];
if (huerfanasActivas > 0) alertItems.push(`${huerfanasActivas} huerfanas`);
if (discrepanciasMerge > 0) alertItems.push(`${discrepanciasMerge} discrepancias`);
if (pctBajo > 5) alertItems.push(`${pctBajo}% baja`);
if (enriqAltaPrioridad > 5) alertItems.push(`${enriqAltaPrioridad} sin dev`);
if (parseFloat(pctHuerfanas) > 5) alertItems.push(`${pctHuerfanas}% sin match`);
if (parseFloat(pctSinDesarrollador) > 10) alertItems.push(`${pctSinDesarrollador}% proy sin dev`);
if (sinPrecio > 10) alertItems.push(`${sinPrecio} sin precio`);
if (!enrichmentLlmOk) alertItems.push('LLM enrich no corrio');
if (!discoveryAlqOk) alertItems.push('discovery alq no corrio');
if (!enrichmentAlqOk) alertItems.push('enrich alq no corrio');
if (!mergeAlqOk) alertItems.push('merge alq no corrio');
if (llmPendientesVenta > 50) alertItems.push(`${llmPendientesVenta} pend LLM`);

const alertasTexto = alertItems.length > 0 ? alertItems.join(' · ') : 'Sin alertas';

// ===== EMOJIS =====
const ok = '\u2705';
const warn = '\u26A0\uFE0F';
const no = '\u274C';

// ===== FECHA =====
const fecha = new Date().toLocaleDateString('es-BO', {
  day: '2-digit',
  month: 'short',
  year: 'numeric'
}).replace('.', '');

// ===== CONSTRUIR MENSAJE =====
const mensaje = `*SICI Auditoria  ${fecha}*\n    ${alertasTexto}\n\n    *PROPIEDADES*\n    ${completadas} completadas / ${total} total\n    ${matcheadas} matcheadas (${pctMatch}%)\n    ${sinMatch} sin match  ${excluidasOp} excluidas\n    +${creadas24h} creadas  +${enriquecidas24h} enriquecidas\n\n    *CALIDAD*\n    Alto ${scoreAlto} (${pctAlto}%)  Medio ${scoreMedio} (${pctMedio}%)  Bajo ${scoreBajo} (${pctBajo}%)\n    Faltantes: zona ${sinZona}  dorms ${sinDorms}  nombre ${sinNombreField}  precio ${sinPrecio}\n\n    *MATCHING*\n    24h: ${sugerencias24h} -> ${aprobadas24h} ok  ${rechazadas24h} no\n    Tasa: ${tasaAprobacion}  Pendientes: ${pendientesMatching}\n    Nocturno 4AM: ${matchingNocturnoOk ? ok : warn}\n\n    *REVISION HUMANA*\n    Matching: ${pendientesMatching}  Huerfanas: ${huerfanasActivas}\n    Discrepancias: ${discrepanciasMerge}\n\n    *ALQUILER*\n    ${alqCompletadas} completadas  ${alqMatcheadas} matcheadas (${alqPctMatch}%)\n    +${alqCreadas24h} creadas 24h  ${alqLlmEnriched} LLM enriched\n\n    *LLM ENRICHMENT*\n    Venta: ${llmEnrichedVenta} enriquecidas  ${llmPendientesVenta} pendientes\n    Enrichment LLM 2:15AM: ${enrichmentLlmOk ? ok : warn} (${horasSinEnrichmentLlm}h)\n\n    *PROYECTOS*\n    ${proyTotal} total  GPS: ${proyGpsVerificado} (${pctGpsVerificado}%)\n    Con dev: ${proyConDesarrollador}  Sin dev: ${proySinDesarrollador} (${pctSinDesarrollador}%)\n    Place ID: ${proyConPlaceId}  Pend Google: ${proyPendientesGoogle}\n\n    *ENRIQUECIMIENTO PM*\n    Sin desarrollador: ${enriqPendientes}\n    Alta prioridad: ${enriqAltaPrioridad}  Nuevos: ${enriqNuevos}\n\n    *TC DINAMICO*\n    Paralelo: ${tcParalelo}  Oficial: ${tcOficial}\n    Binance 24h: ${consultasBinance24h}  ${tcDinamicoOk ? ok : warn}\n\n    *HEALTH — Venta*\n    ${discoveryOk ? ok : warn} Discovery  ${enrichmentOk ? ok : warn} Enrich  ${enrichmentLlmOk ? ok : warn} LLM  ${mergeOk ? ok : warn} Merge  ${matchingNocturnoOk ? ok : warn} Matching\n    *HEALTH — Alquiler*\n    ${discoveryAlqOk ? ok : warn} Discovery  ${enrichmentAlqOk ? ok : warn} Enrich  ${mergeAlqOk ? ok : warn} Merge  ${verificadorAlqOk ? ok : warn} Verificador\n    *HEALTH — Global*\n    ${tcDinamicoOk ? ok : warn} TC Dinamico\n\n    _${totalSugerencias} sugerencias  SICI v3.0_`;

// ===== SNAPSHOT para BD =====
const snapshot = {
  fecha: new Date().toISOString().split('T')[0],
  props_total: total,
  props_completadas: completadas,
  props_nuevas: nuevas,
  props_nuevas_venta: pendientesEnrich,
  props_inactivas: inactivoPending + inactivoConfirmed,
  props_inactivo_pending: inactivoPending,
  props_inactivo_confirmed: inactivoConfirmed,
  props_matcheadas: matcheadas,
  props_sin_match: sinMatch,
  props_con_nombre: conNombre,
  props_con_zona: completadas - sinZona,
  props_creadas_24h: creadas24h,
  props_enriquecidas_24h: enriquecidas24h,
  pct_match_completadas: parseFloat(pctMatch),
  pct_nombre_completadas: parseFloat(pctNombre),
  pct_huerfanas: parseFloat(pctHuerfanas),
  score_alto: scoreAlto,
  score_medio: scoreMedio,
  score_bajo: scoreBajo,
  pct_alto: pctAlto,
  pct_medio: pctMedio,
  pct_bajo: pctBajo,
  sin_zona: sinZona,
  sin_dormitorios: sinDorms,
  sin_nombre: sinNombreField,
  sin_precio: sinPrecio,
  discrepancias_merge: discrepanciasMerge,
  excluidas_matching: 0,
  alq_completadas: alqCompletadas,
  alq_creadas_24h: alqCreadas24h,
  alq_llm_enriched: alqLlmEnriched,
  alq_matcheadas: alqMatcheadas,
  llm_enriched_venta: llmEnrichedVenta,
  llm_pendientes_venta: llmPendientesVenta,
  match_total: totalSugerencias,
  match_24h: sugerencias24h,
  match_aprobadas_24h: aprobadas24h,
  match_rechazadas_24h: rechazadas24h,
  match_pendientes: pendientesMatching,
  huerfanas_activas: huerfanasActivas,
  tasa_aprobacion_24h: tasaAprobacion === 'N/A' ? null : parseInt(tasaAprobacion),
  proy_total: proyTotal,
  proy_activos: proyActivos,
  proy_gps_verificado: proyGpsVerificado,
  proy_con_place_id: proyConPlaceId,
  proy_pendientes_google: proyPendientesGoogle,
  proy_con_desarrollador: proyConDesarrollador,
  proy_sin_desarrollador: proySinDesarrollador,
  pct_sin_desarrollador: parseFloat(pctSinDesarrollador),
  pct_gps_verificado: parseFloat(pctGpsVerificado),
  horas_sin_enrichment: horasSinEnrichment,
  horas_sin_merge: horasSinMerge,
  horas_sin_enrichment_llm: horasSinEnrichmentLlm,
  matching_nocturno_ok: matchingNocturnoOk,
  discovery_ok: discoveryOk,
  enrichment_ok: enrichmentOk,
  enrichment_llm_ok: enrichmentLlmOk,
  merge_ok: mergeOk,
  tc_dinamico_ok: tcDinamicoOk
};

return {
  json: {
    mensaje,
    slack_payload: {
      text: mensaje
    },
    snapshot,
    alertas: alertItems,
    tieneAlertas: alertItems.length > 0
  }
};
